// ── TIER ALGORITHM ────────────────────────────────────────────────────────────
// COLE decides the tier — the buyer never chooses in the popup
// Rule: $67 only for SAFE/CLEAR outcomes. ANY risk = $147.

function recommendedTier(
  bracketStatus: BracketStatus,
  holdingMonths: number | string,
  gainAmount: number | string,
  heldInCompany: boolean,
): PackTier {
  // holdingMonths under 12 OR heldInCompany OR gainAmount over 300000 → tier2. Otherwise tier1.
    if ((holdingMonths as number) < 12 || (gainAmount as number) > 300000 || heldInCompany === true) return 147;
  // Default: safe = $67, any risk = $147
  return (bracketStatus === "clear" || bracketStatus === "out_of_scope" || bracketStatus === "pass")
    ? 67
    : 147;
}

